Rule.Source:
import sailpoint.object.Scope; 
  Scope returningScope = null;
  String scopeByManager = null; 

  if(null != identity.getManager()) {
    scopeByManager = identity.getManager().getDisplayName(); 
  }  
  if(null == scopeByManager ) {
    Scope admins = context.getObjectByName(Scope.class, "Admins"); 
    if(admins == null) {
      admins = new Scope("Admins");
      context.saveObject(admins); 
      String adminsId = admins.getId(); 
      admins.setDisplayName("Admins Scope"); 
      admins.setPath(adminsId); admins.setAssignedScope(admins); 
      context.saveObject(admins); context.commitTransaction();
    } returningScope = admins; 
  }else if(null != scopeByManager) { 
    Scope scope = context.getObjectByName(Scope.class, scopeByManager); 
    if(scope == null) { 
      scope = new Scope(scopeByManager); 
      context.saveObject(scope); 
      String scopeId = scope.getId(); 
      scope.setDisplayName(scopeByManager+" Manager Scope"); 
      scope.setPath(scopeId); 
      scope.setAssignedScope(scope); 
      context.saveObject(scope); 
      context.commitTransaction();
    } returningScope = scope; 
  } 
  return returningScope;
